   164	  .card-name { font-weight: 700; font-size: 14px; margin-bottom: 2px; letter-spacing: -0.2px; }
   165	  .card-desc { font-size: 11px; color: var(--text-dim); line-height: 1.45; margin-bottom: 14px; }
   166	
   167	  /* ── RATING DOTS ── */
   168	  .rating { display: flex; align-items: center; gap: 4px; }
   169	  .rating-label {
   170	    font-family: 'Space Mono', monospace; font-size: 8px; letter-spacing: 0.8px;
   171	    text-transform: uppercase; color: var(--text-muted); width: 48px; flex-shrink: 0;
   172	  }
   173	  .rating-label.end { text-align: right; }
   174	  .dots { display: flex; gap: 5px; flex: 1; justify-content: center; }
   175	  .dot {
   176	    width: 28px; height: 28px; border-radius: 50%; border: 2px solid var(--border);
   177	    cursor: pointer; transition: all 0.2s; position: relative; background: transparent;
   178	  }
