                      background: level === key ? `${arc.color}18` : "rgba(255,255,255,0.03)",
                      border: `1px solid ${level === key ? arc.color + "50" : "rgba(255,255,255,0.06)"}`,
                      color: level === key ? "#fff" : "rgba(255,255,255,0.4)",
                      borderRadius: 6, padding: "7px 12px",
                      fontSize: 11, fontWeight: level === key ? 600 : 400,
                      cursor: "pointer", transition: "all 0.3s ease",
                      fontFamily: "'DM Sans', sans-serif",
                    }}
                  >
                    {name}
                  </button>
                ))}
              </div>
            </div>

            {/* Compare */}
            <div style={{ marginBottom: 28 }}>
              <label style={{ display: "block", fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginBottom: 10, fontWeight: 500 }}>
                Compare With
              </label>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                <button
                  onClick={() => setCompareArchetype(null)}
                  style={{
                    background: !compareArchetype ? "rgba(255,255,255,0.08)" : "rgba(255,255,255,0.03)",
                    border: `1px solid ${!compareArchetype ? "rgba(255,255,255,0.2)" : "rgba(255,255,255,0.06)"}`,
                    color: !compareArchetype ? "#fff" : "rgba(255,255,255,0.35)",
                    borderRadius: 6, padding: "6px 12px", fontSize: 11,
                    cursor: "pointer", transition: "all 0.3s ease",
                    fontFamily: "'DM Sans', sans-serif",
                  }}
                >
                  None
                </button>
                {Object.entries(ARCHETYPES).filter(([k]) => k !== archetype).map(([key, a]) => (
                  <button
                    key={key}
                    onClick={() => setCompareArchetype(key)}
                    style={{
                      background: compareArchetype === key ? `${a.color}18` : "rgba(255,255,255,0.03)",
                      border: `1px solid ${compareArchetype === key ? a.color + "50" : "rgba(255,255,255,0.06)"}`,
                      borderRadius: 6, padding: "5px 10px",
                      cursor: "pointer", transition: "all 0.3s ease",
                      display: "flex", alignItems: "center", gap: 6,
                      fontFamily: "'DM Sans', sans-serif",
                    }}
                  >
                    <div style={{ width: 6, height: 6, borderRadius: "50%", background: a.color }} />
                    <span style={{ fontSize: 10, color: compareArchetype === key ? "#fff" : "rgba(255,255,255,0.35)" }}>
                      {a.name.split(" ")[0]}
                    </span>
                  </button>
                ))}
              </div>
            </div>

            {/* Peak Strengths */}
            <div style={{
              background: "rgba(255,255,255,0.02)",
              border: "1px solid rgba(255,255,255,0.06)",
              borderRadius: 10, padding: 16,
            }}>
              <label style={{ display: "block", fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginBottom: 12, fontWeight: 500 }}>
                Peak Strengths
              </label>
              {topCompetencies.map((c, i) => (
                <div key={c.name} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: i < 2 ? 10 : 0 }}>
                  <span style={{ fontFamily: "'Syne', sans-serif", fontSize: 22, fontWeight: 800, color: arc.color, minWidth: 30, transition: "color 0.6s" }}>
                    {c.value}
                  </span>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 12, fontWeight: 500, color: "rgba(255,255,255,0.7)" }}>{c.name}</div>
                    <div style={{
                      marginTop: 4, height: 3, borderRadius: 2,
                      background: "rgba(255,255,255,0.06)",
                      overflow: "hidden",
                    }}>
                      <div style={{
                        height: "100%", borderRadius: 2,
                        width: `${c.value * 10}%`,
                        background: `linear-gradient(90deg, ${arc.color}, ${arc.color}88)`,
                        transition: "all 0.8s cubic-bezier(0.16,1,0.3,1)",
                      }} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Right: Chart */}
          <div ref={containerRef} style={{ flex: 1, minWidth: 300, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
            <div style={{ display: "flex", gap: 24, marginBottom: 16, flexWrap: "wrap", justifyContent: "center" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <div style={{ width: 20, height: 3, borderRadius: 2, background: arc.color, transition: "background 0.6s" }} />
                <span style={{ fontSize: 11, color: "rgba(255,255,255,0.5)" }}>{arc.name}</span>
              </div>
              {cmpArc && (
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <div style={{ width: 20, height: 3, borderRadius: 2, background: cmpArc.color, opacity: 0.6, borderTop: `1px dashed ${cmpArc.color}` }} />
                  <span style={{ fontSize: 11, color: "rgba(255,255,255,0.5)" }}>{cmpArc.name}</span>
                </div>
              )}
            </div>

            <RoseChart
              data={currentData}
              color={arc.color}
              glow={arc.glow}
              compareData={compareData}
              compareColor={cmpArc?.color}
              compareGlow={cmpArc?.glow}
              size={chartSize}
            />

            <p style={{ fontSize: 11, color: "rgba(255,255,255,0.2)", marginTop: 12, textAlign: "center", fontStyle: "italic", maxWidth: 380 }}>
              Scores represent relative competency emphasis — not absolute skill. Every archetype needs all ten; the shape shows where each one leads.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById("root")).render(<App />);
</script>
</body>
</html>
