const border = { style: BorderStyle.SINGLE, size: 1, color: BORDER_CLR };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: WHITE };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };
const cellMargins = { top: 80, bottom: 80, left: 120, right: 120 };

function heading(text, level) {
  return new Paragraph({
    heading: level,
    children: [new TextRun({ text })],
  });
}

function body(text, opts = {}) {
  return new Paragraph({
    spacing: { after: 180 },
    ...opts,
    children: [new TextRun({ text, size: 22, font: "Arial", ...opts.run })],
  });
}

function bodyRuns(runs, opts = {}) {
  return new Paragraph({
    spacing: { after: 180 },
    ...opts,
    children: runs.map(r => new TextRun({ size: 22, font: "Arial", ...r })),
  });
}

function bullet(text, ref = "bullets", level = 0) {
  return new Paragraph({
    numbering: { reference: ref, level },
    spacing: { after: 80 },
    children: [new TextRun({ text, size: 22, font: "Arial" })],
  });
}

function bulletRuns(runs, ref = "bullets", level = 0) {
  return new Paragraph({
    numbering: { reference: ref, level },
    spacing: { after: 80 },
    children: runs.map(r => new TextRun({ size: 22, font: "Arial", ...r })),
  });
}

function numbered(text, ref = "numbers", level = 0) {
  return new Paragraph({
    numbering: { reference: ref, level },
    spacing: { after: 80 },
    children: [new TextRun({ text, size: 22, font: "Arial" })],
  });
}

function spacer(pts = 200) {
  return new Paragraph({ spacing: { after: pts }, children: [] });
}

function divider() {
  return new Paragraph({
    spacing: { before: 200, after: 200 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: ACCENT2, space: 8 } },
    children: [],
  });
}

function makeCell(content, width, opts = {}) {
  const children = Array.isArray(content)
    ? content
    : [new Paragraph({ children: [new TextRun({ text: content, size: 20, font: "Arial", ...(opts.run || {}) })], alignment: opts.align })];
  return new TableCell({
    borders,
    width: { size: width, type: WidthType.DXA },
    margins: cellMargins,
    shading: opts.shading ? { fill: opts.shading, type: ShadingType.CLEAR } : undefined,
    children,
  });
}

function makeHeaderCell(text, width) {
  return makeCell(text, width, { shading: DARK_BG, run: { bold: true, color: WHITE, size: 20 } });
}

// ─── DOCUMENT ───
const doc = new Document({
