  { id: 'consumer', title: 'Consumer / B2C Products', sub: 'Consumer apps, e-commerce, social', color: '#38bdf8', glow: 'rgba(56,189,248,0.08)' },
  { id: 'zero_to_one', title: '0 → 1 Product Work', sub: 'Built from concept to launch', color: '#818cf8', glow: 'rgba(129,140,248,0.08)' },
