];

function getArchetype(scores) {
  const vals = COMPETENCIES.map(c => scores[c.id] || 0);
  const total = vals.reduce((a, b) => a + b, 0);
  if (total === 0) return null;
  const avg = total / vals.length;
  const variance = vals.reduce((s, v) => s + Math.pow(v - avg, 2), 0) / vals.length;
  if (variance < 0.8 && total >= 20) return ARCHETYPES.find(a => a.name === 'The Generalist');
  let best = null, bestS = -1;
  for (const arch of ARCHETYPES) {
    if (!arch.peaks.length) continue;
    const s = arch.peaks.reduce((sum, p) => sum + (scores[p] || 0), 0) / arch.peaks.length;
    if (s > bestS) { bestS = s; best = arch; }
  }
  return best;
}

/* ── COMPONENTS ── */
function RatingDots({ compId, value, color, glow, onRate }) {
  return (
    <div className="rating">
      <span className="rating-label">Novice</span>
      <div className="dots">
        {[1,2,3,4,5].map(n => (
          <button key={n} className={`dot${value >= n ? ' filled' : ''}`}
            style={{ '--dot-color': color, '--dot-glow': glow }}
            onClick={() => onRate(compId, value === n ? 0 : n)}>
            <span className="dot-num">{n}</span>
          </button>
        ))}
      </div>
      <span className="rating-label end">Expert</span>
      <div className={`score-val${value ? ' visible' : ''}`} style={{ color }}>{value || ''}</div>
    </div>
  );
}

function RadarChart({ scores, size = 240 }) {
  const c = size / 2, r = size / 2 - 28, levels = 5;
  const ids = COMPETENCIES.map(x => x.id);
  const step = (Math.PI * 2) / ids.length;
  const pt = (i, v) => {
    const a = step * i - Math.PI / 2, d = (v / 5) * r;
    return { x: c + d * Math.cos(a), y: c + d * Math.sin(a) };
  };
  const rings = Array.from({ length: levels }, (_, i) => {
    const rr = ((i + 1) / levels) * r;
    return ids.map((_, j) => { const a = step * j - Math.PI / 2; return `${c + rr * Math.cos(a)},${c + rr * Math.sin(a)}`; }).join(' ');
  });
  const dataPts = ids.map((id, i) => { const p = pt(i, scores[id] || 0); return `${p.x},${p.y}`; }).join(' ');
  const labels = COMPETENCIES.map((comp, i) => {
    const a = step * i - Math.PI / 2, lr = r + 16;
    return { x: c + lr * Math.cos(a), y: c + lr * Math.sin(a), t: comp.name.split(' ')[0], color: comp.color };
  });
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {rings.map((p, i) => <polygon key={i} points={p} fill="none" stroke="#252836" strokeWidth="1" opacity={0.4 + i * 0.1} />)}
      {ids.map((_, i) => { const a = step * i - Math.PI / 2; return <line key={i} x1={c} y1={c} x2={c + r * Math.cos(a)} y2={c + r * Math.sin(a)} stroke="#252836" strokeWidth="1" />; })}
      <polygon points={dataPts} fill="url(#rg)" stroke="#ff4d6a" strokeWidth="1.5" opacity="0.85" />
      {ids.map((id, i) => { const p = pt(i, scores[id] || 0); return scores[id] > 0 ? <circle key={id} cx={p.x} cy={p.y} r="3" fill={COMPETENCIES[i].color} /> : null; })}
      {labels.map((l, i) => <text key={i} x={l.x} y={l.y} textAnchor="middle" dominantBaseline="middle" fill={l.color} fontSize="7" fontFamily="Space Mono, monospace" opacity="0.6">{l.t}</text>)}
      <defs><linearGradient id="rg" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" stopColor="#ff4d6a" stopOpacity="0.2" /><stop offset="50%" stopColor="#a78bfa" stopOpacity="0.1" /><stop offset="100%" stopColor="#00e5c7" stopOpacity="0.15" /></linearGradient></defs>
    </svg>
  );
}

function ProgressRing({ pct, color, size = 100 }) {
  const stroke = 5, r = (size - stroke * 2) / 2, circ = 2 * Math.PI * r;
  const offset = circ - (pct / 100) * circ;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="#1e2133" strokeWidth={stroke} />
      <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color || '#ff4d6a'} strokeWidth={stroke}
        strokeDasharray={circ} strokeDashoffset={offset} strokeLinecap="round"
        transform={`rotate(-90 ${size/2} ${size/2})`} style={{ transition: 'stroke-dashoffset 0.6s ease' }} />
      <text x={size/2} y={size/2 - 6} textAnchor="middle" dominantBaseline="middle"
        fill={color || '#ff4d6a'} fontFamily="Bebas Neue, sans-serif" fontSize="28">{pct}</text>
      <text x={size/2} y={size/2 + 12} textAnchor="middle" dominantBaseline="middle"
        fill="#3d4162" fontFamily="Space Mono, monospace" fontSize="8">/ 100</text>
    </svg>
